+// resolvePageLimit applies the supplied limit (falling back to fallback when
+// limit <= 0) and clamps the result to maxSQLLimit. #6598-#6602.
+func resolvePageLimit(limit, fallback int) int {
+	if limit <= 0 {
+		limit = fallback
+	}
+	return clampLimit(limit)
+}
